	(4, 4, 'es', '{"css": ".section-gap{margin-top:80px}.direction-ltr{direction:ltr}.direction-rtl{direction:rtl}.inline-col-wrapper{display:grid;grid-template-columns:auto 1fr;grid-gap:60px;align-items:center}.inline-col-wrapper .inline-col-image-wrapper{overflow:hidden}.inline-col-wrapper .inline-col-image-wrapper img{max-width:100%;height:auto;border-radius:16px;text-indent:-9999px}.inline-col-wrapper .inline-col-content-wrapper{display:flex;flex-wrap:wrap;gap:20px;max-width:464px}.inline-col-wrapper .inline-col-content-wrapper .inline-col-title{max-width:442px;font-size:60px;font-weight:400;color:#060c3b;line-height:70px;font-family:DM Serif Display;margin:0}.inline-col-wrapper .inline-col-content-wrapper .inline-col-description{margin:0;font-size:18px;color:#6e6e6e;font-family:Poppins}@media (max-width:991px){.inline-col-wrapper{grid-template-columns:1fr;grid-gap:16px}.inline-col-wrapper .inline-col-content-wrapper{gap:10px}} @media (max-width:768px){.inline-col-wrapper .inline-col-image-wrapper img {width:100%;} .inline-col-wrapper .inline-col-content-wrapper .inline-col-title{font-size:28px !important;line-height:normal !important}} @media (max-width:525px){.inline-col-wrapper .inline-col-content-wrapper .inline-col-title{font-size:20px !important;} .inline-col-description{font-size:16px} .inline-col-wrapper{grid-gap:10px}}", "html": "<div class=\\"section-gap bold-collections container\\">\\n                                <div class=\\"inline-col-wrapper\\">\\n                                    <div class=\\"inline-col-image-wrapper\\">\\n                                        <img src=\\"\\" data-src=\\"storage/theme/6/3SWVAWhJ58J0PHVAdD41t2motESA2Lm5WLFZuAtL.webp\\" class=\\"lazy\\" width=\\"632\\" height=\\"510\\" alt=\\"¡Prepárate para nuestras nuevas Colecciones Audaces!\\">\\n                                    </div>\\n\\n                                    <div class=\\"inline-col-content-wrapper\\">\\n                                        <h2 class=\\"inline-col-title\\"> ¡Prepárate para nuestras nuevas Colecciones Audaces! </h2> \\n                                        \\n                                        <p class=\\"inline-col-description\\">¡Presentamos Nuestras Nuevas Colecciones Audaces! Eleva tu estilo con diseños atrevidos y declaraciones vibrantes. Explora patrones llamativos y colores audaces que redefinen tu armario. ¡Prepárate para abrazar lo extraordinario!</p>\\n                                        \\n                                        <a href=\\"#wellness\\">\\n                                            <button class=\\"primary-button max-md:rounded-lg max-md:px-4 max-md:py-2.5 max-md:text-sm\\">Ver Colecciones</button>\\n                                        </a>\\n                                    </div>\\n                                </div>\\n                            </div>"}'),
	(5, 5, 'es', '{"css": ".section-game {overflow: hidden;}.section-title,.section-title h2{font-weight:400;font-family:DM Serif Display}.section-title{margin-top:80px;padding-left:15px;padding-right:15px;text-align:center;line-height:90px}.section-title h2{font-size:70px;color:#060c3b;max-width:595px;margin:auto}.collection-card-wrapper{display:flex;flex-wrap:wrap;justify-content:center;gap:30px}.collection-card-wrapper .single-collection-card{position:relative}.collection-card-wrapper .single-collection-card img{border-radius:16px;background-color:#f5f5f5;max-width:100%;height:auto;text-indent:-9999px}.collection-card-wrapper .single-collection-card .overlay-text{font-size:50px;font-weight:400;max-width:234px;font-style:italic;color:#060c3b;font-family:DM Serif Display;position:absolute;bottom:30px;left:30px;margin:0}@media (max-width:1024px){.section-title{padding:0 30px}}@media (max-width:991px){.collection-card-wrapper{flex-wrap:wrap}}@media (max-width:768px) {.collection-card-wrapper .single-collection-card .overlay-text{font-size:32px; bottom:20px}.section-title{margin-top:32px}.section-title h2{font-size:28px;line-height:normal}} @media (max-width:525px){.collection-card-wrapper .single-collection-card .overlay-text{font-size:18px; bottom:10px} .section-title{margin-top:28px}.section-title h2{font-size:20px;} .collection-card-wrapper{gap:10px; 15px; row-gap:15px; column-gap:0px;justify-content: space-between;margin-top: 15px;} .collection-card-wrapper .single-collection-card {width:48%;}}", "html": "<div class=\\"section-game\\">\\n                                <div class=\\"section-title\\">\\n                                    <h2>¡El juego con nuestras nuevas adiciones!</h2> \\n                                </div>\\n\\n                                <div class=\\"section-gap container\\">\\n                                    <div class=\\"collection-card-wrapper\\">\\n                                        <div class=\\"single-collection-card\\">\\n                                            <a href=\\"#active-wear\\">\\n                                                <img src=\\"\\" data-src=\\"storage/theme/8/Z99vI4Wrcxqqkztj6A9H4y6UfmqeQPrbEpxpHKeI.webp\\" class=\\"lazy\\" width=\\"615\\" height=\\"600\\" alt=\\"¡El juego con nuestras nuevas adiciones!\\">\\n                                                \\n                                                <h3 class=\\"overlay-text\\">Nuestras Colecciones</h3> \\n                                            </a>\\n                                        </div>\\n\\n                                        <div class=\\"single-collection-card\\">\\n                                            <a href=\\"#active-wear-female\\">\\n                                                <img src=\\"\\" data-src=\\"storage/theme/8/f5j0PNucH6p0zCGnlsOBdWUZU7iXOtSUM7pTzg6v.webp\\" class=\\"lazy\\" width=\\"615\\" height=\\"600\\" alt=\\"¡El juego con nuestras nuevas adiciones!\\">\\n                                                \\n                                                <h3 class=\\"overlay-text\\"> Nuestras Colecciones </h3> \\n                                            </a>\\n                                        </div>\\n                                    </div>\\n                                </div>\\n                            </div>"}'),
	(6, 6, 'es', '{"css": ".section-gap{margin-top:80px}.direction-ltr{direction:ltr}.direction-rtl{direction:rtl}.inline-col-wrapper{display:grid;grid-template-columns:auto 1fr;grid-gap:60px;align-items:center}.inline-col-wrapper .inline-col-image-wrapper{overflow:hidden}.inline-col-wrapper .inline-col-image-wrapper img{max-width:100%;height:auto;border-radius:16px;text-indent:-9999px}.inline-col-wrapper .inline-col-content-wrapper{display:flex;flex-wrap:wrap;gap:20px;max-width:464px}.inline-col-wrapper .inline-col-content-wrapper .inline-col-title{max-width:442px;font-size:60px;font-weight:400;color:#060c3b;line-height:70px;font-family:DM Serif Display;margin:0}.inline-col-wrapper .inline-col-content-wrapper .inline-col-description{margin:0;font-size:18px;color:#6e6e6e;font-family:Poppins}@media (max-width:991px){.inline-col-wrapper{grid-template-columns:1fr;grid-gap:16px}.inline-col-wrapper .inline-col-content-wrapper{gap:10px}}@media (max-width:768px) {.inline-col-wrapper .inline-col-image-wrapper img {max-width:100%;}.inline-col-wrapper .inline-col-content-wrapper{max-width:100%;justify-content:center; text-align:center} .section-gap{padding:0 30px; gap:20px;margin-top:24px} .bold-collections{margin-top:32px;}} @media (max-width:525px){.inline-col-wrapper .inline-col-content-wrapper{gap:10px} .inline-col-wrapper .inline-col-content-wrapper .inline-col-title{font-size:20px;line-height:normal} .section-gap{padding:0 15px; gap:15px;margin-top:10px} .bold-collections{margin-top:28px;}  .inline-col-description{font-size:16px !important} .inline-col-wrapper{grid-gap:15px}", "html": "<div class=\\"section-gap bold-collections container\\">\\n                                <div class=\\"inline-col-wrapper direction-rtl\\">\\n                                    <div class=\\"inline-col-image-wrapper\\">\\n                                        <img src=\\"\\" data-src=\\"storage/theme/10/IYpv3ZYC31ik3Ajx9yQBTRRJ9otgjVhGwSBFZAej.webp\\" class=\\"lazy\\" width=\\"632\\" height=\\"510\\" alt=\\"¡Libera tu Audacia con Nuestra Nueva Colección!\\">\\n                                    </div>\\n\\n                                    <div class=\\"inline-col-content-wrapper direction-ltr\\">\\n                                        <h2 class=\\"inline-col-title\\">¡Libera tu Audacia con Nuestra Nueva Colección!</h2> \\n                                        \\n                                        <p class=\\"inline-col-description\\">Nuestras Colecciones Audaces están aquí para redefinir tu guardarropa con diseños atrevidos y colores vibrantes e impactantes. Desde patrones audaces hasta tonos poderosos, esta es tu oportunidad de romper con lo ordinario y entrar en lo extraordinario.</p>\\n                                        \\n                                        <a href=\\"#electronics\\">\\n                                            <button class=\\"primary-button max-md:rounded-lg max-md:px-4 max-md:py-2.5 max-md:text-sm\\">Ver Colecciones</button>\\n                                        </a>\\n                                    </div>\\n                                </div>\\n                            </div>"}'),
